import type { ReactNode } from 'react';
import type { ActionFunctionArgs } from 'react-router';
import { useRouteLoaderData, useFetcher } from 'react-router';
import { motion } from 'framer-motion';

import Header from '@components/Header';
import Hero from '@components/Hero';
import ServicesList from '@components/ServicesList';
import Team from '@components/Team';
import Portfolio from '@components/Portfolio';
import ClientTimeline from '@components/ClientTimeline';
import InteractiveEstimator from '@components/InteractiveEstimator';
import Testimonials from '@components/Testimonials';
import FAQAccordion from '@components/FAQAccordion';
import ConsultationForm from '@components/ConsultationForm';
import Footer from '@components/Footer';

export function meta() {
  return [
    { title: "tbats.dev | Premium Web Development & Design Studio" },
    { name: "description", content: "Premium web development and design agency crafting high-converting, blazing-fast, and visually stunning digital experiences." },
  ];
}

const ScrollReveal = ({ children }: { children: ReactNode }) => (
  <motion.div
    initial={{ opacity: 0, y: 40 }}
    whileInView={{ opacity: 1, y: 0 }}
    viewport={{ once: true, margin: '-50px' }}
    transition={{ duration: 0.7, ease: 'easeOut' }}
  >
    {children}
  </motion.div>
);

export async function action({ request }: ActionFunctionArgs) {
  const formData = await request.formData();
  const intent = formData.get("intent");

  if (intent === "theme") {
    const theme = formData.get("theme");
    if (theme === "light" || theme === "dark") {
      return new Response(JSON.stringify({ success: true }), {
        headers: {
          "Set-Cookie": `theme=${theme}; Path=/; Max-Age=31536000; SameSite=Lax`,
          "Content-Type": "application/json",
        },
      });
    }
    return new Response(JSON.stringify({ error: "Invalid theme" }), { status: 400 });
  }

  if (intent === "contact") {
    const userName = formData.get("user_name");
    const userEmail = formData.get("user_email");
    const projectBudget = formData.get("project_budget");
    const projectDesc = formData.get("project_desc");

    if (!userName || !userEmail || !projectDesc) {
      return { contactError: "Please fill in all required fields." };
    }

    try {
      const serviceId = process.env.EMAILJS_SERVICE_ID || process.env.VITE_EMAILJS_SERVICE_ID || 'service_tbats';
      const templateId = process.env.EMAILJS_TEMPLATE_ID || process.env.VITE_EMAILJS_TEMPLATE_ID || 'template_tbats';
      const publicKey = process.env.EMAILJS_PUBLIC_KEY || process.env.VITE_EMAILJS_PUBLIC_KEY || 'YOUR_PUBLIC_KEY';
      const privateKey = process.env.EMAILJS_PRIVATE_KEY;

      const payload = {
        service_id: serviceId,
        template_id: templateId,
        user_id: publicKey,
        ...(privateKey ? { accessToken: privateKey } : {}),
        template_params: {
          user_name: userName.toString(),
          user_email: userEmail.toString(),
          project_budget: projectBudget ? projectBudget.toString() : "",
          project_desc: projectDesc.toString(),
        },
      };

      const res = await fetch("https://api.emailjs.com/api/v1.0/email/send", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(payload),
      });

      if (!res.ok) {
        const errText = await res.text();
        console.error("EmailJS REST API error response:", errText);
        return { contactError: "Failed to send request. Please try again or email us directly." };
      }

      return { contactSuccess: true };
    } catch (err) {
      console.error("EmailJS submit error:", err);
      return { contactError: "Failed to send request. Please try again or email us directly." };
    }
  }

  return new Response("Unknown intent", { status: 400 });
}

export default function LandingRoute() {
  const rootData = useRouteLoaderData("root") as { theme: 'light' | 'dark' } | null;
  const theme = rootData?.theme || "dark";
  const fetcher = useFetcher();

  const setTheme = (newTheme: 'light' | 'dark') => {
    void fetcher.submit(
      { intent: "theme", theme: newTheme },
      { method: "post" }
    );
  };

  return (
    <div style={{ position: 'relative', overflow: 'hidden', zIndex: 1 }}>
      <Header theme={theme} setTheme={setTheme} />
      <Hero />

      <div className="section-divider" />
      <ScrollReveal>
        <ServicesList />
      </ScrollReveal>
      
      <div className="section-divider" />
      <ScrollReveal>
        <Portfolio />
      </ScrollReveal>

      <div className="section-divider" />
      <ScrollReveal>
        <ClientTimeline />
      </ScrollReveal>

      <div className="section-divider" />
      <ScrollReveal>
        <ConsultationForm />
      </ScrollReveal>

      <div className="section-divider" />
      <ScrollReveal>
        <InteractiveEstimator />
      </ScrollReveal>

      <div className="section-divider" />
      <ScrollReveal>
        <Team />
      </ScrollReveal>

      <div className="section-divider" />
      <ScrollReveal>
        <Testimonials />
      </ScrollReveal>

      <div className="section-divider" />
      <ScrollReveal>
        <FAQAccordion />
      </ScrollReveal>

      <div className="section-divider" />
      <Footer />
    </div>
  );
}
