import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import Container from '@components/ui/Container';
import Button from '@components/ui/Button';
import styles from './Header.module.css';

interface HeaderProps {
  theme: 'light' | 'dark';
  setTheme: (_theme: 'light' | 'dark') => void;
}

export default function Header({ theme, setTheme }: HeaderProps) {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <nav className="glass-nav">
      <Container className={styles.navContainer}>
        <div className={styles.logoContainer}>
          <span className={`material-symbols-outlined ${styles.logoIcon}`} style={{ fontSize: '28px' }}>
            code_blocks
          </span>
          <span className={styles.logoText}>
            tbats<span className={styles.logoDot}>.dev</span>
          </span>
        </div>
        
        {/* Desktop Nav */}
        <div className={styles.desktopNav}>
          <div className={styles.navLinks}>
            <a href="#services" className={styles.navLink}>Services</a>
            <a href="#portfolio" className={styles.navLink}>Sandbox</a>
            <a href="#process" className={styles.navLink}>Process</a>
            <a href="#contact" className={styles.navLink}>Contact</a>
            <a href="#pricing" className={styles.navLink}>Pricing</a>
            <a href="#about" className={styles.navLink}>About</a>
          </div>
          
          {/* Custom style toggler for color theme */}
          <div className={styles.themeToggleWrapper}>
            {/* Light/Dark Toggle */}
            <motion.button
              onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')}
              className={`${styles.themeButton} clickable`}
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
            >
              <span className="material-symbols-outlined" style={{ fontSize: '18px' }}>
                {theme === 'dark' ? 'light_mode' : 'dark_mode'}
              </span>
            </motion.button>
          </div>

          <Button as="a" href="#contact" variant="primary" size="sm">
            Start a Project
          </Button>
        </div>

        {/* Mobile Nav Toggle */}
        <button 
          className={`${styles.mobileNavToggle} clickable`}
          onClick={() => setIsOpen(!isOpen)}
        >
          <span className="material-symbols-outlined" style={{ fontSize: '28px' }}>
            {isOpen ? 'close' : 'menu'}
          </span>
        </button>
      </Container>

      {/* Mobile Menu */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            className={styles.mobileMenu}
          >
            <a href="#services" onClick={() => setIsOpen(false)} className={styles.mobileNavLink}>Services</a>
            <a href="#portfolio" onClick={() => setIsOpen(false)} className={styles.mobileNavLink}>Sandbox</a>
            <a href="#process" onClick={() => setIsOpen(false)} className={styles.mobileNavLink}>Process</a>
            <a href="#contact" onClick={() => setIsOpen(false)} className={styles.mobileNavLink}>Contact</a>
            <a href="#pricing" onClick={() => setIsOpen(false)} className={styles.mobileNavLink}>Pricing</a>
            <a href="#about" onClick={() => setIsOpen(false)} className={styles.mobileNavLink}>About</a>
            
            {/* Style Toggles in Mobile */}
            <div className={styles.mobileMenuActions}>
              <motion.button
                onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')}
                className={`${styles.mobileThemeButton} clickable`}
                whileTap={{ scale: 0.95 }}
              >
                <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>
                  {theme === 'dark' ? 'light_mode' : 'dark_mode'}
                </span>
              </motion.button>
            </div>

            <Button
              as="a"
              href="#contact"
              variant="primary"
              onClick={() => setIsOpen(false)}
              style={{ textAlign: 'center', marginTop: '1rem', justifyContent: 'center' }}
            >
              Start a Project
            </Button>
          </motion.div>
        )}
      </AnimatePresence>
    </nav>
  );
}